def encode(message):
    vowels = "aeiouAEIOU"
    result = []

    for char in message:
        if char in vowels:
            shifted = chr(ord(char) + 2)
            result.append(shifted.swapcase())
        else:
            result.append(char.swapcase())

    return "".join(result)
