def right_angle_triangle(a, b, c):
    sides = sorted([a, b, c])

    if sides[0] <= 0:
        return False

    if sides[0] + sides[1] <= sides[2]:
        return False

    return abs((sides[0] ** 2 + sides[1] ** 2) - sides[2] ** 2) <= 1e-9
